      getState() {
        return { ...state };
      },
      destroy() {}
    };
  }

  const vertexSource = `
    attribute vec2 aPosition;

    void main() {
      gl_Position = vec4(aPosition, 0.0, 1.0);
    }
  `;

  const fragmentSource = `
    precision highp float;

    uniform vec2 uResolution;
    uniform float uTime;
    uniform float uPulse;
    uniform float uPop;
    uniform float uSymmetry;
    uniform float uCandy;

    const float PI = 3.14159265359;
    const float TAU = 6.28318530718;

    float hash(vec2 p) {
      return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453123);
    }

    mat2 rotate2d(float a) {
      float s = sin(a);
      float c = cos(a);
      return mat2(c, -s, s, c);
    }

    vec2 kaleid(vec2 p, float folds) {
      float r = length(p);
      float a = atan(p.y, p.x);
      float sector = TAU / folds;
      a = abs(mod(a + sector * 0.5, sector) - sector * 0.5);
      return vec2(cos(a), sin(a)) * r;
    }

    float hydraOsc(vec2 p, float frequency, float sync, float offset) {
      vec2 q = p * rotate2d(offset * 0.9);
      return 0.5 + 0.5 * sin((q.x + q.y * sync) * frequency + offset);
    }

    float hydraShape(vec2 p, float sides, float radius, float blur) {
      float a = atan(p.x, p.y) + PI;
      float r = TAU / sides;
      float d = cos(floor(0.5 + a / r) * r - a) * length(p);
      return 1.0 - smoothstep(radius, radius + blur, d);
    }

    float ring(vec2 p, float radius, float width) {
      return 1.0 - smoothstep(width, width + 0.012, abs(length(p) - radius));
    }

    vec3 palette(float x) {
      vec3 pink = vec3(1.0, 0.08, 0.58);
      vec3 yellow = vec3(1.0, 0.92, 0.12);
      vec3 aqua = vec3(0.0, 0.82, 1.0);
      vec3 lime = vec3(0.44, 1.0, 0.18);
      vec3 orange = vec3(1.0, 0.42, 0.05);
      vec3 a = mix(pink, yellow, smoothstep(0.0, 0.28, fract(x)));
      vec3 b = mix(aqua, lime, smoothstep(0.28, 0.64, fract(x)));
      return mix(a, mix(b, orange, 0.22), smoothstep(0.24, 0.92, fract(x)));
    }

    void main() {
      vec2 uv = (gl_FragCoord.xy * 2.0 - uResolution.xy) / min(uResolution.x, uResolution.y);
      vec2 raw = uv;
      float t = uTime;
      float pulse = smoothstep(0.0, 1.0, uPulse);

      vec2 modulator = vec2(
        hydraOsc(uv + t * 0.07, 6.0 + uCandy * 8.0, 0.7, t * 1.4),
        hydraOsc(uv.yx - t * 0.04, 5.0 + uPop * 9.0, 1.1, -t * 1.1)
      ) - 0.5;

      uv += modulator * (0.18 + uPop * 0.16 + pulse * 0.04);
      uv = kaleid(uv * (1.0 + pulse * 0.04), max(3.0, uSymmetry));
      uv *= rotate2d(t * (0.13 + uCandy * 0.18));

      float oscA = hydraOsc(uv, 13.0 + uPop * 18.0, 0.9 + uCandy * 0.8, t * 2.3);
      float oscB = hydraOsc(uv.yx + modulator * 0.38, 8.0 + uCandy * 13.0, 1.45, -t * 1.8);
      float star = hydraShape(uv * 1.05, 5.0 + floor(uCandy * 4.0), 0.38 + pulse * 0.04, 0.022);
      float flower = hydraShape(kaleid(uv * 1.32 + modulator * 0.16, 6.0), 6.0, 0.43, 0.035);
      float target = ring(raw + modulator * 0.1, 0.44 + pulse * 0.05, 0.022 + uPop * 0.016);

      vec2 dotGrid = fract((raw + modulator * 0.08) * (9.0 + uPop * 15.0)) - 0.5;
      float dots = 1.0 - smoothstep(0.12 + uCandy * 0.05, 0.18 + uCandy * 0.05, length(dotGrid));
      float poster = smoothstep(0.44, 0.58, oscA * 0.64 + oscB * 0.36);
      float ink = smoothstep(0.76, 0.84, abs(oscA - oscB) + star * 0.22 + target * 0.32);
      float confetti = step(0.965 - uPop * 0.02, hash(floor((raw + t * 0.035) * 18.0)));

      vec3 base = palette(oscA * 0.34 + oscB * 0.28 + length(raw) * 0.22 + t * 0.065 + uCandy * 0.2);
      vec3 second = palette(oscB * 0.46 + star * 0.25 + t * 0.11 + 0.36);
      vec3 color = mix(base, second, poster);
      color = mix(color, vec3(1.0, 0.96, 0.16), star * (0.42 + pulse * 0.22));
      color = mix(color, vec3(0.0, 0.90, 1.0), flower * 0.34);
      color += dots * vec3(1.0, 1.0, 1.0) * (0.08 + uPop * 0.16);
