  try {
    program = createProgram();
  } catch (error) {
    ctx.domRoot.innerHTML = `<pre style="box-sizing:border-box;width:100%;height:100%;white-space:pre-wrap;color:#fecaca;background:#17080a;padding:12px;border-radius:8px">${error.message}</pre>`;
